import { useEffect, useState } from "react";
import axios from "axios";
import Api from "../api/Api";

export default function DriverCompletedTasks() {
  const [tasks, setTasks] = useState([]);

const getCompletedTasks = async () => {
  try {
    const res = await axios.get(Api.completed_Task);

    console.log("Completed Tasks Response:", res.data);

    setTasks(res.data.requests);
  } catch (error) {
    console.log(error);
  }
};

  useEffect(() => {
    getCompletedTasks();
  }, []);

  return (
    <div className="min-h-screen bg-[#4CBB17]/20 p-8">
      <h1 className="text-4xl font-bold text-green-900 mb-8 text-center">
        Completed Tasks
      </h1>

      {tasks.length === 0 ? (
        <div className="bg-white p-8 rounded-xl shadow text-center">
          No Completed Tasks Found
        </div>
      ) : (
        <div className="space-y-5">
          {tasks.map((task) => (
            <div
              key={task._id}
              className="bg-white rounded-2xl shadow-lg p-6"
            >
              <p className="text-sm text-gray-600 mb-2">
                <span className="font-bold">
                  Request ID:
                </span>{" "}
                #{task._id.slice(-4)}
              </p>

              <p className="font-bold text-green-700 mb-3">
                📍 {task.location?.location}
              </p>

              <div className="grid md:grid-cols-2 gap-3">
                <p>
                  <strong>Created:</strong>{" "}
                  {task.createdAt
                    ? new Date(task.createdAt).toLocaleString()
                    : "-"}
                </p>

                <p>
                  <strong>Scheduled:</strong>{" "}
                  {task.scheduledAt
                    ? new Date(task.scheduledAt).toLocaleString()
                    : "-"}
                </p>

                <p>
                  <strong>Arrived:</strong>{" "}
                  {task.arrivedAt
                    ? new Date(task.arrivedAt).toLocaleString()
                    : "-"}
                </p>

                <p>
                  <strong>Completed:</strong>{" "}
                  {task.completedAt
                    ? new Date(task.completedAt).toLocaleString()
                    : "-"}
                </p>
              </div>

              <div className="mt-4">
                <span className="bg-green-100 text-green-700 px-4 py-2 rounded-full font-semibold">
                  Completed
                </span>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
